// 5. 初始化
async function initApp() {
  const storedData = await db.get({
    categories: DEFAULT_CATEGORIES,
    prompts: [],
    promptVersion: 0
  });

  let prompts = storedData.prompts;
  // 版本升级，重刷 29 个提示词
  if (storedData.promptVersion < PROMPT_VERSION || prompts.length === 0) {
    prompts = DEFAULT_PROMPTS;
    await db.set({ promptVersion: PROMPT_VERSION, prompts: prompts });
  }

  let cats = storedData.categories;
  // 确保「置顶」永远存在且排在第一位
  if (!cats.some(c => c.id === 'pinned')) {
    cats.unshift({ id: 'pinned', name: '置顶' });
  } else {
    const pIdx = cats.findIndex(c => c.id === 'pinned');
    if (pIdx > 0) {
      const pCat = cats.splice(pIdx, 1)[0];
      cats.unshift(pCat);
    }
  }

  state.categories = cats;
  state.prompts = prompts;
  
  bindEvents();
  renderCategories();
  renderPrompts();
  initDragToScroll(); // 初始化鼠标横向滑动分类
}


// 6. 数据保存与重绘
async function saveAndSync() {
  await db.set({
    categories: state.categories,
    prompts: state.prompts
  });
  renderCategories();
  renderPrompts();
}

// 7. 页面渲染
function renderCategories() {
  const activeId = state.activeTab;
  let html = '';
  
  state.categories.forEach(cat => {
    html += `<button class="category-tab ${activeId === cat.id ? 'active' : ''}" data-id="${cat.id}">${escapeHtml(cat.name)}</button>`;
  });
  
  DOM.categoriesList.innerHTML = html;
  
  // 渲染编辑下拉框 (不包含置顶)
  let selectHtml = '';
  state.categories.forEach(cat => {
    if (cat.id !== 'pinned') {
      selectHtml += `<option value="${cat.id}">${escapeHtml(cat.name)}</option>`;
    }
  });
  DOM.selectPromptCategory.innerHTML = selectHtml;
}

