  const activeId = state.activeTab;
  
  const filteredPrompts = activeId === 'pinned'
    ? state.prompts.filter(p => p.isPinned)
    : state.prompts.filter(p => p.categoryId === activeId);
  
  if (filteredPrompts.length === 0) {
    DOM.promptsContainer.innerHTML = '';
    DOM.emptyState.classList.remove('hidden');
    return;
  }
  
  DOM.emptyState.classList.add('hidden');
  
  // 非置顶分类下支持拖拽
  const isDraggable = activeId !== 'pinned';
  
  let html = '';
