        <button class="btn-pin ${p.isPinned ? 'pinned' : ''} btn-toggle-pin" data-id="${p.id}" title="${p.isPinned ? '取消置顶' : '固定置顶'}">
          <svg xmlns="http://www.w3.org/2000/svg" width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="18" y1="2" x2="6" y2="2"></line><line x1="12" y1="2" x2="12" y2="18"></line><path d="M12 18v4"></path><path d="M4 12c1.5-2.5 3-4 8-4s6.5 1.5 8 4H4z"></path></svg>
        </button>
